package main
import (
    "fmt"
    "sync"
)

var counter int = 0
var mu sync.Mutex // Our lock!

func incrementer(wg *sync.WaitGroup) {
    // 1. Lock the door!
    mu.Lock()

    // 2. Safely modify the variable
    counter++

    // 3. Unlock the door so others can enter!
    mu.Unlock()

    wg.Done()
}

func main() {
    var wg sync.WaitGroup
    // Start 1000 concurrent workers!
    for i := 0; i < 1000; i++ {
        wg.Add(1)
        go incrementer(&wg)
    }

    wg.Wait() // wait for all to finish
    fmt.Println("Final Counter:", counter)
}
